5: class DNSCache {
6:   constructor(options = {}) {
7:     this.ttl = options.ttl || 300000;
8:     this.cache = new Map();
9:   }
10: 
11:   resolve(hostname) {
12:     return new Promise((resolve, reject) => {
13:       const cached = this.cache.get(hostname);
14:       if (cached && Date.now() - cached.timestamp < this.ttl) {
15:         return resolve(cached.addresses);
16:       }
17: 
18:       dns.resolve4(hostname, (err, addresses) => {
19:         if (err) return reject(err);
20:         this.cache.set(hostname, {
21:           addresses,
22:           timestamp: Date.now(),
23:         });
24:         resolve(addresses);
25:       });
26:     });
27:   }
28: 
29:   lookup(hostname) {
30:     return new Promise((resolve, reject) => {
31:       const cached = this.cache.get(`lookup:${hostname}`);
32:       if (cached && Date.now() - cached.timestamp < this.ttl) {
33:         return resolve(cached.result);
34:       }
35: 
36:       dns.lookup(hostname, (err, address, family) => {
37:         if (err) return reject(err);
38:         const result = { address, family };
39:         this.cache.set(`lookup:${hostname}`, {
40:           result,
41:           timestamp: Date.now(),
42:         });
43:         resolve(result);
44:       });
45:     });
46:   }
